const aq = $input.all()[0]?.json || {};
const wx = $input.all()[1]?.json || {};

const temp = wx.current?.temperature_2m || 15;
const humidity = wx.current?.relative_humidity_2m || 60;
const wind = wx.current?.wind_speed_10m || 10;
const precip = wx.current?.precipitation || 0;
const aqi = aq.current?.european_aqi || 0;
const pm25 = aq.current?.pm2_5 || 0;

// Fire Danger Index (simplified McArthur)
const recentRain = (wx.daily?.precipitation_sum || []).slice(0, 3).reduce((s, v) => s + (v || 0), 0);
const fdi = (temp * 0.3) + ((100 - humidity) * 0.3) + (wind * 0.2) - (recentRain * 2);

let severity = 'Low';
let probability = 0.05;
let action = 'monitor';
if (fdi > 50 || aqi > 100) { severity = 'Critical'; probability = 0.90; action = 'issue_critical_alert'; }
else if (fdi > 35 || aqi > 75) { severity = 'High'; probability = 0.65; action = 'issue_warning'; }
else if (fdi > 20 || aqi > 50) { severity = 'Medium'; probability = 0.35; action = 'issue_advisory'; }

return [{ json: {
  incidentType: 'wildfire',
  severity,
  probability,
  fdi: Math.round(fdi * 10) / 10,
  aqi,
  pm25,
  temp,
  humidity,
  wind,
  recentRainMm: Math.round(recentRain * 10) / 10,
  action,
  shouldAlert: severity !== 'Low',
  timestamp: new Date().toISOString()
}}];
